con:config.script:
import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def source = new XmlDataReader(context, dataFile)

source.load(testRunner.testCase.getName())

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

context.allRecords = ca.getContentRecords()

con:config.script:
def headerAuthorTime ='/urn:imagingOutcome/urn1:imagingOutcomeHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def resultTime = '/urn:imagingOutcome/urn1:imagingOutcomeBody/urn1:resultTime'
def referralAuthorTime ='/urn:imagingOutcome/urn1:imagingOutcomeBody/urn1:referral/urn1:accountableHealthcareProfessional/urn1:authorTime'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.dates) {
	def headerAuthorTimes = context.allRecords.collect { record -> record.firstElementAt(headerAuthorTime) }
	def resultTimes = context.allRecords.collect { record -> record.firstElementAt(resultTime) }
	def referralAuthorTimes = context.allRecords.collect { record -> record.firstElementAt(referralAuthorTime) }

	context.dates = headerAuthorTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += resultTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += referralAuthorTimes.findAll().collect{ it[0..7] }.unique()

	context.dates = context.dates.findAll().collect{ it[0..7] }.unique()
	log.info "Unika datum: " + context.dates

	if (!context.dates) {
		testRunner.fail("No data")
	}
}

context.datePeriodStart = context.dates.pop()
context.datePeriodEnd = context.datePeriodStart

[context.datePeriodStart, context.datePeriodEnd]

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions def ca = new ContentAssertions(context, messageExchange)
def authorTimeHead ='/urn:imagingOutcome/urn1:imagingOutcomeHeader/urn1:accountableHealthcareProfessional/urn1:authorTime' def authorTimeReferral ='/urn:imagingOutcome/urn1:imagingOutcomeBody/urn1:referral/urn1:accountableHealthcareProfessional/urn1:authorTime' def resultTime = '/urn:imagingOutcome/urn1:imagingOutcomeBody/urn1:resultTime' def id = '/urn:imagingOutcome/urn1:imagingOutcomeHeader/urn1:documentId'
def condition = { record -> def before = [authorTimeHead, authorTimeReferral, resultTime].every { xPath -> record.firstElementAt(xPath) == null || record.timestampIsBefore(xPath, context.datePeriodStart) } def after = [authorTimeHead, authorTimeReferral, resultTime].every { xPath -> record.firstElementAt(xPath) == null || record.timestampIsAfter(xPath, context.datePeriodEnd) } return !before && !after }
def recordInfo = { record -> sprintf("DocumentId %s (authorTimeHeader:%s authorTimeReferral:%s resultTime:%s)", [id, authorTimeHead, authorTimeReferral, resultTime].collect{record.firstElementAt(it)}) }
ca.assertFilteredResponse(context.allRecords, condition, recordInfo)

con:config.script:
if (context.dates.any()) {
	testRunner.gotoStepByName( "Calculate interval")
}
else if (testRunner.getResults().any{it.getStatus().toString() == 'FAILED'}) {
	testRunner.fail("One or more steps failed")
}

