con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

context.allRecords = ca.getContentRecords()

con:config.script:
def authorTimeHead ='/urn:imagingOutcome/urn1:imagingOutcomeHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def authorTimeReferral ='/urn:imagingOutcome/urn1:imagingOutcomeBody/urn1:referral/urn1:accountableHealthcareProfessional/urn1:authorTime'
def resultTime = '/urn:imagingOutcome/urn1:imagingOutcomeBody/urn1:resultTime'
def dateFormat = 'yyyyMMdd'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.dates) {
	def authorTimeHeads = context.allRecords.collect { record -> record.firstElementAt(authorTimeHead) }
	def authorTimeReferrals = context.allRecords.collect { record -> record.firstElementAt(authorTimeReferral) }
	def resultTimes = context.allRecords.collect { record -> record.firstElementAt(resultTime) }
	def dates = (authorTimeHeads+authorTimeReferrals+resultTimes).findAll().collect { it[0..7] }.unique()

	def firstDate = Date.parse(dateFormat, dates.min())
	def lastDate = Date.parse(dateFormat, dates.max())
	def dateDiff = lastDate - firstDate
	context.dates =  []
	(2 * context.numberOfIntervals.toInteger()).times {
		def randomOffset = (Math.random() * (dateDiff+1)).toInteger()
		def randomDate = firstDate.plus(randomOffset).format(dateFormat)
		context.dates.add(randomDate)
	}
}

def dates = [context.dates.pop(), context.dates.pop()].sort()

context.datePeriodStart = dates[0]
context.datePeriodEnd = dates[-1]

[context.datePeriodStart, context.datePeriodEnd]

