// create groovyUtils and XmlHolder for response of Request 1 request
def groovyUtils = new com.eviware.soapui.support.GroovyUtils( context )
def holder = groovyUtils.getXmlHolder( "Call GetImagingOutcome 1#Response" )
def path = testRunner.testCase.testSuite.project.getPropertyValue("RecordElementPath")
holder.declareNamespace("urn", "urn:riv:clinicalprocess:healthcond:actoutcome:GetImagingOutcomeResponder:1")
holder.declareNamespace("urn1", "urn:riv:clinicalprocess:healthcond:actoutcome:3")

log.info path

def numberOfposts = holder["count(${path})"]
context.testCase.setPropertyValue("Poster request 1",numberOfposts)
log.info numberOfposts

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

// create groovyUtils and XmlHolder for response of Request 1 request
def groovyUtils = new com.eviware.soapui.support.GroovyUtils( context )
def holder = groovyUtils.getXmlHolder( "Call GetImagingOutcome 2#Response" )
def path = messageExchange.modelItem.testStep.testCase.testSuite.project.getPropertyValue("RecordElementPath")
holder.declareNamespace("urn", "urn:riv:clinicalprocess:healthcond:actoutcome:GetImagingOutcomeResponder:1")
holder.declareNamespace("urn1", "urn:riv:clinicalprocess:healthcond:actoutcome:3")

log.info path

def numberOfposts = holder["count(${path})"]
context.testCase.setPropertyValue("Poster request 2",numberOfposts)

def AntalPosterRequest1 = context.testCase.getPropertyValue("Poster request 1")
def AntalPosterRequest2 = context.testCase.getPropertyValue("Poster request 2")
log.info "Post 1: " + AntalPosterRequest1
log.info "Post 2: " +  AntalPosterRequest2

assert AntalPosterRequest1 > AntalPosterRequest2 : "Antalet poster efter filtrering är inte färre än antalet poster före filtrering"

